  1→import { createContext, useContext, useReducer } from 'react';
  2→import { createProject } from '@/domain/models';
  3→import { createDuplicatedFloor, getDefaultFloorName, getFloorElevation, getFloorLevelIndex, shiftFloorAbsoluteElements, shiftFloorElevationData, sortFloors } from '@/domain/floorModels';
  4→import { detachColumnAttachments, syncWallAttachmentPoints } from '@/geometry/wallColumnGeometry';
  5→import { syncStairLandingAttachment } from '@/geometry/landingGeometry';
  6→
  7→const ProjectContext = createContext(null);
  8→const HISTORY_LIMIT = 100;
  9→
 10→function snapshotProject(project) {
 11→  return JSON.stringify(project);
 12→}
 13→
 14→function applyProjectUpdate(state, nextProject, recordHistory = true) {
 15→  const nextSnapshot = snapshotProject(nextProject);
 16→  const history = recordHistory
 17→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 18→    : state.history;
 19→
 20→  return {
 21→    ...state,
 22→    history,
 23→    future: recordHistory ? [] : state.future,
 24→    project: nextProject,
 25→    isDirty: nextSnapshot !== state.savedSnapshot,
 26→  };
 27→}
 28→
 29→function updateFloor(state, floorId, updater, recordHistory = true, options = {}) {
 30→  const nextFloors = state.project.floors.map((floor) => (
 31→    floor.id === floorId ? updater(floor) : floor
 32→  ));
 33→
 34→  return applyProjectUpdate(state, {
 35→    ...state.project,
 36→    updatedAt: new Date().toISOString(),
 37→    floors: options.sort ? sortFloors(nextFloors) : nextFloors,
 38→  }, recordHistory);
 39→}
 40→
 41→function replaceFloors(state, floors, recordHistory = true) {
 42→  return applyProjectUpdate(state, {
 43→    ...state.project,
 44→    updatedAt: new Date().toISOString(),
 45→    floors: sortFloors(floors),
 46→  }, recordHistory);
 47→}
 48→
 49→function replaceDeletedFloorReferences(project, deletedFloorId, fallbackFloorId) {
 50→  return {
 51→    ...project,
 52→    floors: project.floors.map((floor) => ({
 53→      ...floor,
 54→      stairs: (floor.stairs || []).map((stair) => ({
 55→        ...stair,
 56→        floorRelation: {
 57→          fromFloorId: stair.floorRelation?.fromFloorId === deletedFloorId
 58→            ? fallbackFloorId
 59→            : (stair.floorRelation?.fromFloorId ?? floor.id),
 60→          toFloorId: stair.floorRelation?.toFloorId === deletedFloorId
 61→            ? fallbackFloorId
 62→            : (stair.floorRelation?.toFloorId ?? floor.id),
 63→        },
 64→      })),
 65→    })),
 66→    sheets: (project.sheets || []).map((sheet) => ({
 67→      ...sheet,
 68→      viewports: (sheet.viewports || []).map((viewport) => ({
 69→        ...viewport,
 70→        sourceFloorId: viewport.sourceFloorId === deletedFloorId
 71→          ? fallbackFloorId
 72→          : viewport.sourceFloorId,
 73→        sourceRefId: viewport.sourceFloorId === deletedFloorId
 74→          ? null
 75→          : viewport.sourceRefId,
 76→      })),
 77→    })),
 78→  };
 79→}
 80→
 81→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 82→  const nextWall = { ...existingWall, ...wallUpdate };
 83→
 84→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 85→    nextWall.startAttachment = null;
 86→  }
 87→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 88→    nextWall.endAttachment = null;
 89→  }
 90→
 91→  return syncWallAttachmentPoints(nextWall, columns);
 92→}
 93→
 94→function projectReducer(state, action) {
 95→  switch (action.type) {
 96→    case 'PROJECT_NEW': {
 97→      const newProject = {
 98→        ...action.project,
 99→        floors: sortFloors(action.project.floors || []),
100→      };
101→      return {
102→        project: newProject,
103→        isDirty: false,
104→        lastSavedAt: null,
105→        savedSnapshot: snapshotProject(newProject),
106→        history: [],
107→        future: [],
108→      };
109→    }
110→
111→    case 'PROJECT_LOAD': {
112→      const loadedProject = {
113→        ...action.project,
114→        floors: sortFloors(action.project.floors || []),
115→      };
116→      return {
117→        project: loadedProject,
118→        isDirty: false,
119→        lastSavedAt: action.savedAt || null,
120→        savedSnapshot: snapshotProject(loadedProject),
121→        history: [],
122→        future: [],
123→      };
124→    }
125→
126→    case 'PROJECT_SET_NAME':
127→      return applyProjectUpdate(state, {
128→        ...state.project,
129→        name: action.name,
130→        updatedAt: new Date().toISOString(),
131→      });
132→
133→    case 'FLOOR_ADD':
134→      return replaceFloors(state, [...state.project.floors, action.floor]);
135→
136→    case 'FLOOR_UPDATE':
137→      return updateFloor(state, action.floor.id, (floor) => {
138→        const mergedFloor = {
139→          ...floor,
140→          ...action.floor,
141→        };
142→        const nextElevation = getFloorElevation(mergedFloor);
143→        const deltaElevation = nextElevation - getFloorElevation(floor);
144→        return {
145→          ...shiftFloorAbsoluteElements({
146→            ...mergedFloor,
147→            elevation: getFloorElevation(floor),
148→          }, deltaElevation),
149→          elevation: nextElevation,
150→        };
151→      }, true, { sort: true });
152→
153→    case 'FLOOR_DUPLICATE': {
154→      const duplicatedFloor = action.floor;
155→      const elevationShift = duplicatedFloor.floorToFloorHeight ?? 0;
156→      const insertionLevelIndex = getFloorLevelIndex(duplicatedFloor);
157→
158→      const shiftedFloors = state.project.floors.map((floor) => {
159→        if (getFloorLevelIndex(floor) < insertionLevelIndex) return floor;
160→
161→        const previousLevelIndex = getFloorLevelIndex(floor);
162→        return shiftFloorElevationData({
163→          ...floor,
164→          name: floor.name === getDefaultFloorName(previousLevelIndex)
165→            ? getDefaultFloorName(previousLevelIndex + 1)
166→            : floor.name,
167→          levelIndex: previousLevelIndex + 1,
168→        }, elevationShift);
169→      });
170→
171→      return replaceFloors(state, [...shiftedFloors, duplicatedFloor]);
172→    }
173→
174→    case 'FLOOR_DELETE': {
175→      if (state.project.floors.length <= 1) return state;
176→
177→      const nextProject = replaceDeletedFloorReferences(
178→        {
179→          ...state.project,
180→          floors: state.project.floors.filter((floor) => floor.id !== action.floorId),
181→        },
182→        action.floorId,
183→        action.fallbackFloorId
184→      );
185→
186→      return applyProjectUpdate(state, {
187→        ...nextProject,
188→        updatedAt: new Date().toISOString(),
189→        floors: sortFloors(nextProject.floors),
190→      });
191→    }
192→
193→    case 'SHEET_ADD':
194→      return applyProjectUpdate(state, {
195→        ...state.project,
196→        updatedAt: new Date().toISOString(),
197→        sheets: [...(state.project.sheets || []), action.sheet],
198→      });
199→
200→    case 'SHEET_UPDATE':
201→      return applyProjectUpdate(state, {
202→        ...state.project,
203→        updatedAt: new Date().toISOString(),
204→        sheets: (state.project.sheets || []).map((sheet) => (
205→          sheet.id === action.sheet.id ? { ...sheet, ...action.sheet } : sheet
206→        )),
207→      });
208→
209→    case 'SHEET_DELETE':
210→      return applyProjectUpdate(state, {
211→        ...state.project,
212→        updatedAt: new Date().toISOString(),
213→        sheets: (state.project.sheets || []).filter((sheet) => sheet.id !== action.sheetId),
214→      });
215→
216→    case 'SHEET_VIEWPORT_ADD':
217→      return applyProjectUpdate(state, {
218→        ...state.project,
219→        updatedAt: new Date().toISOString(),
220→        sheets: (state.project.sheets || []).map((sheet) => (
221→          sheet.id === action.sheetId
222→            ? { ...sheet, viewports: [...(sheet.viewports || []), action.viewport] }
223→            : sheet
224→        )),
225→      });
226→
227→    case 'SHEET_VIEWPORT_UPDATE':
228→      return applyProjectUpdate(state, {
229→        ...state.project,
230→        updatedAt: new Date().toISOString(),
231→        sheets: (state.project.sheets || []).map((sheet) => (
232→          sheet.id === action.sheetId
233→            ? {
234→                ...sheet,
235→                viewports: (sheet.viewports || []).map((viewport) => (
236→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
237→                )),
238→              }
239→            : sheet
240→        )),
241→      });
242→
243→    case 'SHEET_VIEWPORT_DELETE':
244→      return applyProjectUpdate(state, {
245→        ...state.project,
246→        updatedAt: new Date().toISOString(),
247→        sheets: (state.project.sheets || []).map((sheet) => (
248→          sheet.id === action.sheetId
249→            ? {
250→                ...sheet,
251→                viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId),
252→              }
253→            : sheet
254→        )),
255→      });
256→
257→    case 'WALL_ADD':
258→      return updateFloor(state, action.floorId, f => ({
259→        ...f,
260→        walls: [...f.walls, syncWallAttachmentPoints(action.wall, f.columns || [])],
261→      }));
262→
263→    case 'WALL_UPDATE':
264→      return updateFloor(state, action.floorId, f => ({
265→        ...f,
266→        walls: f.walls.map(w => (
267→          w.id === action.wall.id
268→            ? mergeWallUpdate(w, action.wall, f.columns || [])
269→            : w
270→        )),
271→      }));
272→
273→    case 'WALL_DELETE': {
274→      const wallId = action.wallId;
275→      return updateFloor(state, action.floorId, f => ({
276→        ...f,
277→        walls: f.walls.filter(w => w.id !== wallId),
278→        doors: f.doors.filter(d => d.wallId !== wallId),
279→        windows: f.windows.filter(w => w.wallId !== wallId),
280→      }));
281→    }
282→
283→    case 'DOOR_ADD':
284→      return updateFloor(state, action.floorId, f => ({
285→        ...f,
286→        doors: [...f.doors, action.door],
287→      }));
288→
289→    case 'DOOR_UPDATE':
290→      return updateFloor(state, action.floorId, f => ({
291→        ...f,
292→        doors: f.doors.map(d => d.id === action.door.id ? { ...d, ...action.door } : d),
293→      }));
294→
295→    case 'DOOR_DELETE':
296→      return updateFloor(state, action.floorId, f => ({
297→        ...f,
298→        doors: f.doors.filter(d => d.id !== action.doorId),
299→      }));
300→
301→    case 'WINDOW_ADD':
302→      return updateFloor(state, action.floorId, f => ({
303→        ...f,
304→        windows: [...f.windows, action.window],
305→      }));
306→
307→    case 'WINDOW_UPDATE':
308→      return updateFloor(state, action.floorId, f => ({
309→        ...f,
310→        windows: f.windows.map(w => w.id === action.window.id ? { ...w, ...action.window } : w),
311→      }));
312→
313→    case 'WINDOW_DELETE':
314→      return updateFloor(state, action.floorId, f => ({
315→        ...f,
316→        windows: f.windows.filter(w => w.id !== action.windowId),
317→      }));
318→
319→    case 'BEAM_ADD':
320→      return updateFloor(state, action.floorId, f => ({
321→        ...f,
322→        beams: [...(f.beams || []), action.beam],
323→      }));
324→
325→    case 'BEAM_UPDATE':
326→      return updateFloor(state, action.floorId, f => ({
327→        ...f,
328→        beams: (f.beams || []).map(beam => (
329→          beam.id === action.beam.id ? { ...beam, ...action.beam } : beam
330→        )),
331→      }));
332→
333→    case 'BEAM_DELETE':
334→      return updateFloor(state, action.floorId, f => ({
335→        ...f,
336→        beams: (f.beams || []).filter(beam => beam.id !== action.beamId),
337→      }));
338→
339→    case 'STAIR_ADD':
340→      return updateFloor(state, action.floorId, f => ({
341→        ...f,
342→        stairs: [...(f.stairs || []), action.stair],
343→      }));
344→
345→    case 'STAIR_UPDATE':
346→      return updateFloor(state, action.floorId, f => ({
347→        ...f,
348→        stairs: (f.stairs || []).map(stair => (
349→          stair.id === action.stair.id ? { ...stair, ...action.stair } : stair
350→        )),
351→      }));
352→
353→    case 'STAIR_DELETE':
354→      return updateFloor(state, action.floorId, f => ({
355→        ...f,
356→        stairs: (f.stairs || []).filter(stair => stair.id !== action.stairId),
357→      }));
358→
359→    case 'LANDING_ADD':
360→      return updateFloor(state, action.floorId, f => ({
361→        ...f,
362→        landings: [...(f.landings || []), action.landing],
363→      }));
364→
365→    case 'LANDING_UPDATE': {
366→      return updateFloor(state, action.floorId, f => {
367→        const nextLandings = (f.landings || []).map(l =>
368→          l.id === action.landing.id ? { ...l, ...action.landing } : l
369→        );
370→        // Cascade: sync all stairs attached to this landing
371→        const nextStairs = (f.stairs || []).map(stair => {
372→          const attachedToStart = stair.startLandingAttachment?.landingId === action.landing.id;
373→          const attachedToEnd = stair.endLandingAttachment?.landingId === action.landing.id;
374→          if (!attachedToStart && !attachedToEnd) return stair;
375→          return syncStairLandingAttachment(stair, nextLandings);
376→        });
377→        return { ...f, landings: nextLandings, stairs: nextStairs };
378→      });
379→    }
380→
381→    case 'LANDING_DELETE':
382→      return updateFloor(state, action.floorId, f => ({
383→        ...f,
384→        landings: (f.landings || []).filter(l => l.id !== action.landingId),
385→        stairs: (f.stairs || []).map(stair => {
386→          let next = stair;
387→          if (stair.startLandingAttachment?.landingId === action.landingId) {
388→            next = { ...next, startLandingAttachment: null };
389→          }
390→          if (stair.endLandingAttachment?.landingId === action.landingId) {
391→            next = { ...next, endLandingAttachment: null };
392→          }
393→          return next;
394→        }),
395→      }));
396→
397→    case 'ANNOTATION_ADD':
398→      return updateFloor(state, action.floorId, f => ({
399→        ...f,
400→        annotations: [...(f.annotations || []), action.annotation],
401→      }));
402→
403→    case 'ANNOTATION_UPDATE':
404→      return updateFloor(state, action.floorId, f => ({
405→        ...f,
406→        annotations: (f.annotations || []).map((annotation) => (
407→          annotation.id === action.annotation.id ? { ...annotation, ...action.annotation } : annotation
408→        )),
409→      }));
410→
411→    case 'ANNOTATION_DELETE':
412→      return updateFloor(state, action.floorId, f => ({
413→        ...f,
414→        annotations: (f.annotations || []).filter((annotation) => annotation.id !== action.annotationId),
415→      }));
416→
417→    case 'ANNOTATION_SETTINGS_UPDATE':
418→      return updateFloor(state, action.floorId, f => ({
419→        ...f,
420→        annotationSettings: {
421→          ...(f.annotationSettings || {}),
422→          ...action.settings,
423→        },
424→      }));
425→
426→    case 'SLAB_ADD':
427→      return updateFloor(state, action.floorId, f => ({
428→        ...f,
429→        slabs: [...(f.slabs || []), action.slab],
430→      }));
431→
432→    case 'SLAB_UPDATE':
433→      return updateFloor(state, action.floorId, f => ({
434→        ...f,
435→        slabs: (f.slabs || []).map(s =>
436→          s.id === action.slab.id ? { ...s, ...action.slab } : s
437→        ),
438→      }));
439→
440→    case 'SLAB_DELETE':
441→      return updateFloor(state, action.floorId, f => ({
442→        ...f,
443→        slabs: (f.slabs || []).filter(s => s.id !== action.slabId),
444→      }));
445→
446→    case 'SECTION_ADD':
447→      return updateFloor(state, action.floorId, f => ({
448→        ...f,
449→        sectionCuts: [...(f.sectionCuts || []), action.sectionCut],
450→      }));
451→
452→    case 'SECTION_UPDATE':
453→      return updateFloor(state, action.floorId, f => ({
454→        ...f,
455→        sectionCuts: (f.sectionCuts || []).map(s =>
456→          s.id === action.sectionCut.id ? { ...s, ...action.sectionCut } : s
457→        ),
458→      }));
459→
460→    case 'SECTION_DELETE':
461→      return updateFloor(state, action.floorId, f => ({
462→        ...f,
463→        sectionCuts: (f.sectionCuts || []).filter(s => s.id !== action.sectionId),
464→      }));
465→
466→    case 'ROOM_ADD':
467→      return updateFloor(state, action.floorId, f => ({
468→        ...f,
469→        rooms: [...f.rooms, action.room],
470→      }));
471→
472→    case 'ROOM_UPDATE':
473→      return updateFloor(state, action.floorId, f => ({
474→        ...f,
475→        rooms: f.rooms.map(r => r.id === action.room.id ? { ...r, ...action.room } : r),
476→      }));
477→
478→    case 'ROOM_DELETE':
479→      return updateFloor(state, action.floorId, f => ({
480→        ...f,
481→        rooms: f.rooms.filter(r => r.id !== action.roomId),
482→      }));
483→
484→    case 'ROOMS_SET':
485→      return updateFloor(state, action.floorId, f => ({
486→        ...f,
487→        rooms: action.rooms,
488→      }));
489→
490→    case 'FLOOR_REPLACE':
491→      return updateFloor(state, action.floorId, () => ({
492→        ...action.floor,
493→      }), true, { sort: true });
494→
495→    case 'COLUMN_ADD':
496→      return updateFloor(state, action.floorId, f => ({
497→        ...f, columns: [...(f.columns || []), action.column],
498→      }));
499→    case 'COLUMN_DUPLICATE':
500→      return updateFloor(state, action.floorId, f => ({
501→        ...f,
502→        columns: [...(f.columns || []), action.column],
503→      }));
504→    case 'COLUMN_UPDATE':
505→      return updateFloor(state, action.floorId, f => {
506→        const nextColumns = (f.columns || []).map(c => (
507→          c.id === action.column.id ? { ...c, ...action.column } : c
508→        ));
509→        return {
510→          ...f,
511→          columns: nextColumns,
512→          walls: f.walls.map(w => syncWallAttachmentPoints(w, nextColumns)),
513→        };
514→      });
515→    case 'COLUMN_DELETE':
516→      return updateFloor(state, action.floorId, f => ({
517→        ...f,
518→        columns: (f.columns || []).filter(c => c.id !== action.columnId),
519→        walls: f.walls.map(w => detachColumnAttachments(w, f.columns || [], action.columnId)),
520→        beams: (f.beams || []).filter(beam => (
521→          beam.startRef?.id !== action.columnId && beam.endRef?.id !== action.columnId
522→        )),
523→      }));
524→
525→    case 'MARK_SAVED':
526→      return {
527→        ...state,
528→        isDirty: false,
529→        lastSavedAt: new Date().toISOString(),
530→        savedSnapshot: snapshotProject(state.project),
531→      };
532→
533→    case 'UNDO': {
534→      if (state.history.length === 0) return state;
535→      const previousProject = state.history[state.history.length - 1];
536→      return {
537→        ...state,
538→        project: previousProject,
539→        history: state.history.slice(0, -1),
540→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
541→        isDirty: snapshotProject(previousProject) !== state.savedSnapshot,
542→      };
543→    }
544→
545→    case 'REDO': {
546→      if (state.future.length === 0) return state;
547→      const nextProject = state.future[0];
548→      return {
549→        ...state,
550→        project: nextProject,
551→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
552→        future: state.future.slice(1),
553→        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
554→      };
555→    }
556→
557→    default:
558→      return state;
559→  }
560→}
561→
562→const initialProject = createProject();
563→
564→const initialState = {
565→  project: initialProject,
566→  isDirty: false,
567→  lastSavedAt: null,
568→  savedSnapshot: snapshotProject(initialProject),
569→  history: [],
570→  future: [],
571→};
572→
573→export function ProjectProvider({ children }) {
574→  const [state, dispatch] = useReducer(projectReducer, initialState);
575→  return (
576→    <ProjectContext.Provider value={{ state, dispatch }}>
577→      {children}
578→    </ProjectContext.Provider>
579→  );
580→}
581→
582→export function useProject() {
583→  const ctx = useContext(ProjectContext);
584→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
585→  const { state, dispatch } = ctx;
586→
587→  const duplicateFloor = (floorId) => {
588→    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
589→    return floor ? createDuplicatedFloor(floor) : null;
590→  };
591→
592→  return {
593→    project: state.project,
594→    isDirty: state.isDirty,
595→    lastSavedAt: state.lastSavedAt,
596→    canUndo: state.history.length > 0,
597→    canRedo: state.future.length > 0,
598→    dispatch,
599→    duplicateFloor,
600→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
601→  };
602→}
