188→          return;
189→        }
190→        if (key === 'x') {
191→          e.preventDefault();
192→          cutSelection();
193→          return;
194→        }
195→        if (key === 'v') {
196→          e.preventDefault();
197→          beginPaste(cursorPosRef.current);
198→          return;
199→        }
